export function getOefenvragenVoorLeerdoel(leerdoelId: string): Oefenvraag[] {
  if (!leerdoelId) return []
  return oefenvragen.filter(v => {
    if (!v.leerdoelId) return false
    return (
      v.leerdoelId === leerdoelId ||
      leerdoelId.startsWith(v.leerdoelId + "-") ||
      v.leerdoelId.startsWith(leerdoelId + "-")
    )
  })
}

export function getOefenvragenVoorVak(vakId: string): Oefenvraag[] {
  return oefenvragen.filter(v => v.vakId === vakId)
}
